--- a/priority_encoder.sv
+++ b/priority_encoder.sv
@@ -1,20 +1,20 @@
 module priority_encoder_8bit (
   input [7:0] req,
   input enable,
   output reg [2:0] priority,
   output reg valid
 );

-  always @(req) begin
+  always @(req or enable) begin
     if (enable) begin
       if (req[7])
         priority = 3'd7;
       else if (req[6])
         priority = 3'd6;
       else if (req[5])
         priority = 3'd5;
       else if (req[4])
         priority = 3'd4;

before_code:
module priority_encoder_8bit (
  input [7:0] req,
  input enable,
  output reg [2:0] priority,
  output reg valid
);

  always @(req) begin
    if (enable) begin
      if (req[7])
        priority = 3'd7;
      else if (req[6])
        priority = 3'd6;
      else if (req[5])
        priority = 3'd5;
      else if (req[4])
        priority = 3'd4;
      else if (req[3])
        priority = 3'd3;
      else if (req[2])
        priority = 3'd2;
      else if (req[1])
        priority = 3'd1;
      else
        priority = 3'd0;
      valid = 1'b1;
    end else begin
      valid = 1'b0;
    end
  end
endmodule

after_code:
module priority_encoder_8bit (
  input [7:0] req,
  input enable,
  output reg [2:0] priority,
  output reg valid
);

  always @(req or enable) begin
    if (enable) begin
      if (req[7])
        priority = 3'd7;
      else if (req[6])
        priority = 3'd6;
      else if (req[5])
        priority = 3'd5;
      else if (req[4])
        priority = 3'd4;
      else if (req[3])
        priority = 3'd3;
      else if (req[2])
        priority = 3'd2;
      else if (req[1])
        priority = 3'd1;
      else
        priority = 3'd0;
      valid = 1'b1;
    end else begin
      valid = 1'b0;
    end
  end
endmodule
